import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Safety Categories","description":"","frontmatter":{},"headers":[],"relativePath":"en/safety/categories.md","filePath":"en/safety/categories.md"}'),o={name:"en/safety/categories.md"};function r(l,e,n,c,p,d){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="safety-categories" tabindex="-1">Safety Categories <a class="header-anchor" href="#safety-categories" aria-label="Permalink to &quot;Safety Categories&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Safety categories define the structure and reliability of safety related control systems.</p><p>They describe how a system is designed to respond to faults and how likely it is to maintain its safety function.</p><p>Categories are used to classify safety performance based on design principles and fault tolerance.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of safety categories is to ensure that safety systems provide the required level of protection.</p><p>They are used to:</p><ul><li>Define the reliability of safety functions</li><li>Guide system design</li><li>Support risk reduction measures</li><li>Ensure compliance with safety standards</li></ul><p>They help match system design to the level of risk.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Safety categories are defined by how the system handles faults and maintains safety functions.</p><h3 id="category-b" tabindex="-1">Category B <a class="header-anchor" href="#category-b" aria-label="Permalink to &quot;Category B&quot;">​</a></h3><p>Basic safety principles are applied.</p><ul><li>No specific fault tolerance</li><li>Failure may lead to loss of safety function</li></ul><p>Used for low risk applications.</p><h3 id="category-1" tabindex="-1">Category 1 <a class="header-anchor" href="#category-1" aria-label="Permalink to &quot;Category 1&quot;">​</a></h3><p>Uses well proven components and principles.</p><ul><li>Improved reliability compared to basic design</li><li>Still no fault detection</li></ul><p>Suitable for low to moderate risk.</p><h3 id="category-2" tabindex="-1">Category 2 <a class="header-anchor" href="#category-2" aria-label="Permalink to &quot;Category 2&quot;">​</a></h3><p>Includes periodic testing of safety functions.</p><ul><li>Faults may be detected during testing</li><li>Safety function may be lost between tests</li></ul><p>Provides higher reliability than Category 1.</p><h3 id="category-3" tabindex="-1">Category 3 <a class="header-anchor" href="#category-3" aria-label="Permalink to &quot;Category 3&quot;">​</a></h3><p>Designed with redundancy.</p><ul><li>Single fault does not lead to loss of safety function</li><li>Some faults may not be detected</li></ul><p>Provides high reliability.</p><h3 id="category-4" tabindex="-1">Category 4 <a class="header-anchor" href="#category-4" aria-label="Permalink to &quot;Category 4&quot;">​</a></h3><p>Highest level of reliability.</p><ul><li>Faults are detected continuously</li><li>Safety function is maintained even with faults</li></ul><p>Used in high risk applications.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Safety categories are used in systems where safety functions are required.</p><p>Typical applications include:</p><ul><li>Emergency stop systems</li><li>Safety interlocks</li><li>Machine guarding systems</li><li>Process safety systems</li></ul><p>They are critical in systems with potential hazards.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><p>Category selection depends on risk assessment.</p><p>Higher categories increase complexity and cost.</p><p>Fault detection and redundancy improve safety performance.</p><p>System design must follow defined principles for each category.</p><p>Compliance with standards is required.</p><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><p>A common mistake is selecting a category without proper risk assessment.</p><p>Do not assume higher category is always better. Match it to the application.</p><p>Ensure all components meet the required category.</p><p>Verify system performance through testing.</p><p>Document safety design clearly for validation and maintenance.</p>',49)])])}const y=a(o,[["render",r]]);export{u as __pageData,y as default};
